19	func TestIntegration_FEAT008BackendOperations(t *testing.T) {
20		skipIntegrationInShort(t)
21		t.Setenv("HOME", t.TempDir())
22		workDir, store := setupIntegrationDir(t)
23	
24		docPath := filepath.Join(workDir, "docs", "palette-alpha.md")
25		if err := os.MkdirAll(filepath.Dir(docPath), 0o755); err != nil {
26			t.Fatal(err)
27		}
28		if err := os.WriteFile(docPath, []byte("---\nddx:\n  id: palette-alpha\n---\n# Palette Alpha\n\nThis body must not be required for command palette indexing.\n"), 0o644); err != nil {
29			t.Fatal(err)
30		}
31	
32		// Place the plugin at the project-local path (FEAT-015: no global installs).
33		pluginRoot := filepath.Join(workDir, ddxroot.DirName, "plugins", "local-ui")
34		if err := os.MkdirAll(filepath.Join(pluginRoot, "skills", "ui-polish"), 0o755); err != nil {
35			t.Fatal(err)
36		}
37		if err := os.WriteFile(filepath.Join(pluginRoot, "package.yaml"), []byte(`name: local-ui
38	version: 1.2.3
39	description: Local UI plugin
40	type: plugin
41	source: file://local-ui
42	api_version: "1"
43	keywords: [ui, local]
44	install:
45	  root:
46	    source: "."
47	    target: ".ddx/plugins/local-ui"
48	`), 0o644); err != nil {
49			t.Fatal(err)
50		}
51		if err := os.WriteFile(filepath.Join(pluginRoot, "skills", "ui-polish", "SKILL.md"), []byte("---\nname: ui-polish\ndescription: Polish UI\n---\n"), 0o644); err != nil {
52			t.Fatal(err)
53		}
54		if err := registry.SaveState(&registry.InstalledState{Installed: []registry.InstalledEntry{{
55			Name:        "local-ui",
56			Version:     "1.2.3",
57			Type:        registry.PackageTypePlugin,
58			Source:      "file://local-ui",
59			InstalledAt: time.Now().UTC(),
60			Files:       []string{pluginRoot},
61		}}}); err != nil {
62			t.Fatal(err)
63		}
64	
65		ready := &bead.Bead{Title: "Palette ready bead", Status: bead.StatusOpen}
66		if err := store.Create(context.Background(), ready); err != nil {
67			t.Fatal(err)
68		}
69		dep := &bead.Bead{Title: "Blocking prerequisite", Status: bead.StatusOpen}
70		if err := store.Create(context.Background(), dep); err != nil {
71			t.Fatal(err)
72		}
73		blocked := &bead.Bead{Title: "Palette blocked bead", Status: bead.StatusOpen}
74		if err := store.Create(context.Background(), blocked); err != nil {
75			t.Fatal(err)
76		}
77		if err := store.DepAdd(context.Background(), blocked.ID, dep.ID); err != nil {
78			t.Fatal(err)
79		}
80		inProgress := &bead.Bead{Title: "Running bead", Status: bead.StatusOpen}
81		if err := store.Create(context.Background(), inProgress); err != nil {
82			t.Fatal(err)
83		}
84		if err := store.Claim(inProgress.ID, "agent-01"); err != nil {
85			t.Fatal(err)
86		}
87		closed := &bead.Bead{Title: "Closed evidence bead", Status: bead.StatusOpen}
88		if err := store.Create(context.Background(), closed); err != nil {
89			t.Fatal(err)
90		}
91		if err := store.AppendEvent(closed.ID, bead.BeadEvent{
92			Kind: "routing",
93			Body: `{"resolved_provider":"openai","resolved_model":"gpt-5"}`,
94		}); err != nil {
95			t.Fatal(err)
96		}
97		if err := store.AppendEvent(closed.ID, bead.BeadEvent{
98			Kind: "cost",
99			Body: `{"attempt_id":"attempt-001","harness":"codex","provider":"openai","model":"gpt-5","input_tokens":1200,"output_tokens":450,"cost_usd":0.0123,"duration_ms":34000,"exit_code":0}`,
100		}); err != nil {
101			t.Fatal(err)
102		}
103		if err := store.Close(context.Background(), closed.ID); err != nil {
104			t.Fatal(err)
105		}
106		started := time.Date(2026, 4, 22, 14, 0, 0, 0, time.UTC)
107		if err := agent.AppendSessionIndex(agent.SessionLogDirForWorkDir(workDir), agent.SessionIndexEntry{
108			ID:           "session-closed",
109			ProjectID:    agent.ProjectIDForPath(workDir),
110			BeadID:       closed.ID,
111			Harness:      "codex",
112			Provider:     "openai",
113			Model:        "gpt-5",
114			StartedAt:    started,
115			EndedAt:      started.Add(34 * time.Second),
116			DurationMS:   34000,
117			CostUSD:      0.0123,
118			CostPresent:  true,
119			InputTokens:  1200,
120			OutputTokens: 450,
121			Outcome:      "success",
122			BundlePath:   filepath.ToSlash(filepath.Join(ddxroot.DirName, "executions", "attempt-001")),
123		}, started); err != nil {
124			t.Fatal(err)
125		}
126	
127		state := newTestStateProvider(workDir, store)
128		projectID := state.projects[0].ID
129		h := newGQLHandler(state, workDir, nil)
130	
131		query := `{
132			queueSummary(projectId: "` + projectID + `") { ready blocked inProgress operatorAttention dependencyWaiting externalBlocked cancelled }
133			efficacyRows { rowKey harness provider model attempts successes successRate medianInputTokens medianOutputTokens medianDurationMs medianCostUsd warning { kind threshold } }
134			efficacyAttempts(rowKey: "codex|openai|gpt-5") { rowKey attempts { beadId outcome durationMs costUsd evidenceBundleUrl } }
135			comparisons { id state armCount }
136			pluginsList { name version installedVersion type description keywords status registrySource diskBytes manifest skills prompts templates }
137			pluginDetail(name: "local-ui") { name version installedVersion type description keywords status registrySource diskBytes manifest skills prompts templates }
138			projectBindings(projectId: "` + projectID + `")
139			paletteSearch(query: "palette") {
140				documents { kind path title }
141				beads { kind id title }
142				actions { kind id label }
143				navigation { kind route title }
144			}
145			personas { name roles description body source bindings { projectId role persona } }
146			bead(id: "` + ready.ID + `") { id title status }
147			worker(id: "worker-missing") { id recentEvents { kind text name inputs output } }
148		}`
149		resp := gqlPost(t, h, query)
150	
151		var data struct {
152			QueueSummary struct {
153				Ready             int `json:"ready"`
154				Blocked           int `json:"blocked"`
155				InProgress        int `json:"inProgress"`
156				OperatorAttention int `json:"operatorAttention"`
157				DependencyWaiting int `json:"dependencyWaiting"`
158				ExternalBlocked   int `json:"externalBlocked"`
159				Cancelled         int `json:"cancelled"`
160			} `json:"queueSummary"`
161			EfficacyRows []struct {
162				RowKey             string   `json:"rowKey"`
163				Attempts           int      `json:"attempts"`
164				Successes          int      `json:"successes"`
165				MedianInputTokens  int      `json:"medianInputTokens"`
166				MedianOutputTokens int      `json:"medianOutputTokens"`
167				MedianDurationMs   int      `json:"medianDurationMs"`
168				MedianCostUsd      *float64 `json:"medianCostUsd"`
169			} `json:"efficacyRows"`
170			EfficacyAttempts struct {
171				Attempts []struct {
172					BeadID            string   `json:"beadId"`
173					Outcome           string   `json:"outcome"`
174					DurationMs        int      `json:"durationMs"`
175					CostUsd           *float64 `json:"costUsd"`
176					EvidenceBundleURL string   `json:"evidenceBundleUrl"`
177				} `json:"attempts"`
178			} `json:"efficacyAttempts"`
179			PluginsList []struct {
180				Name string `json:"name"`
181			} `json:"pluginsList"`
182			PluginDetail struct {
183				Name    string   `json:"name"`
184				Status  string   `json:"status"`
185				Skills  []string `json:"skills"`
186				Version string   `json:"version"`
187			} `json:"pluginDetail"`
188			PaletteSearch struct {
189				Documents []struct {
190					Title string `json:"title"`
191				} `json:"documents"`
192				Beads []struct {
193					ID string `json:"id"`
194				} `json:"beads"`
195			} `json:"paletteSearch"`
196			Bead struct {
197				ID string `json:"id"`
198			} `json:"bead"`
199		}
200		if err := json.Unmarshal(resp["data"], &data); err != nil {
201			t.Fatalf("parse data: %v", err)
202		}
203		if data.QueueSummary.Ready < 2 {
204			t.Fatalf("queueSummary.ready: want at least 2, got %d", data.QueueSummary.Ready)
205		}
206		if data.QueueSummary.Blocked != 0 {
207			t.Fatalf("queueSummary.blocked (externalBlocked): want 0, got %d", data.QueueSummary.Blocked)
208		}
209		if data.QueueSummary.DependencyWaiting != 1 {
210			t.Fatalf("queueSummary.dependencyWaiting: want 1, got %d", data.QueueSummary.DependencyWaiting)
211		}
212		if data.QueueSummary.InProgress != 1 {
213			t.Fatalf("queueSummary.inProgress: want 1, got %d", data.QueueSummary.InProgress)
214		}
215		if len(data.EfficacyRows) == 0 {
216			t.Fatal("expected efficacy rows from session index")
217		}
218		row := data.EfficacyRows[0]
219		if row.RowKey != "codex|openai|gpt-5" || row.Attempts != 1 || row.Successes != 1 || row.MedianInputTokens != 1200 || row.MedianOutputTokens != 450 || row.MedianDurationMs != 34000 {
220			t.Fatalf("unexpected efficacy row: %+v", row)
221		}
222		if row.MedianCostUsd == nil || *row.MedianCostUsd != 0.0123 {
223			t.Fatalf("unexpected median cost: %+v", row.MedianCostUsd)
224		}
225		if len(data.EfficacyAttempts.Attempts) != 1 || data.EfficacyAttempts.Attempts[0].BeadID != closed.ID || data.EfficacyAttempts.Attempts[0].Outcome != "succeeded" {
226			t.Fatalf("unexpected efficacy attempts: %+v", data.EfficacyAttempts.Attempts)
227		}
228		if len(data.PluginsList) == 0 || data.PluginDetail.Name != "local-ui" || data.PluginDetail.Status != "installed" || data.PluginDetail.Version != "1.2.3" || len(data.PluginDetail.Skills) != 1 {
229			t.Fatalf("expected installed plugin data, got %+v", data.PluginDetail)
230		}
231		if len(data.PaletteSearch.Documents) == 0 || len(data.PaletteSearch.Beads) == 0 {
232			t.Fatalf("expected real palette document and bead results, got %+v", data.PaletteSearch)
233		}
234		if data.Bead.ID != ready.ID {
235			t.Fatalf("bead(id): want %q, got %q", ready.ID, data.Bead.ID)
236		}
237	
238		mutationResp := gqlPost(t, h, `mutation {
239			workerDispatch(kind: "realign-specs", projectId: "`+projectID+`") { id state kind }
240			pluginDispatch(name: "local-ui", action: "install", scope: "project") { id state action }
241			comparisonDispatch(arms: [{ model: "gpt-5", prompt: "Summarize file X" }, { model: "claude-sonnet-4-6", prompt: "Summarize file X" }]) { id state armCount }
242			personaBind(role: "code-reviewer", persona: "code-reviewer", projectId: "`+projectID+`") { ok role persona }
243			beadClose(id: "`+ready.ID+`", reason: "done") { id status }
244		}`)
245		var mutationData struct {
246			PluginDispatch struct {
247				ID     string `json:"id"`
248				State  string `json:"state"`
249				Action string `json:"action"`
250			} `json:"pluginDispatch"`
251			ComparisonDispatch struct {
252				ID       string `json:"id"`
253				State    string `json:"state"`
254				ArmCount int    `json:"armCount"`
255			} `json:"comparisonDispatch"`
256		}
257		if err := json.Unmarshal(mutationResp["data"], &mutationData); err != nil {
258			t.Fatalf("parse mutation data: %v", err)
259		}
260		if strings.HasPrefix(mutationData.PluginDispatch.ID, "queued-plugin-") || mutationData.PluginDispatch.State != "installed" || mutationData.PluginDispatch.Action != "install" {
261			t.Fatalf("pluginDispatch did not run the real plugin path: %+v", mutationData.PluginDispatch)
262		}
263		if _, err := os.Stat(filepath.Join(workDir, ddxroot.DirName, "plugin-dispatches", mutationData.PluginDispatch.ID+".json")); err != nil {
264			t.Fatalf("pluginDispatch did not write an audit record: %v", err)
265		}
266		if strings.HasPrefix(mutationData.ComparisonDispatch.ID, "queued-comparison-") || mutationData.ComparisonDispatch.State != "queued" || mutationData.ComparisonDispatch.ArmCount != 2 {
267			t.Fatalf("comparisonDispatch did not create a real queued record: %+v", mutationData.ComparisonDispatch)
268		}
269		comparisonPath := filepath.Join(workDir, ddxroot.DirName, "comparisons", mutationData.ComparisonDispatch.ID+".json")
270		if _, err := os.Stat(comparisonPath); err != nil {
271			t.Fatalf("comparisonDispatch did not write a comparison record: %v", err)
272		}
273	
274		comparisonResp := gqlPost(t, h, `{ comparisons { id state armCount } }`)
275		var comparisonData struct {
276			Comparisons []struct {
277				ID       string `json:"id"`
278				State    string `json:"state"`
279				ArmCount int    `json:"armCount"`
280			} `json:"comparisons"`
281		}
282		if err := json.Unmarshal(comparisonResp["data"], &comparisonData); err != nil {
283			t.Fatalf("parse comparisons data: %v", err)
284		}
285		if len(comparisonData.Comparisons) != 1 || comparisonData.Comparisons[0].ID != mutationData.ComparisonDispatch.ID || comparisonData.Comparisons[0].ArmCount != 2 {
286			t.Fatalf("comparisons did not read back dispatched record: %+v", comparisonData.Comparisons)
287		}
288	
289		cfgData, err := os.ReadFile(filepath.Join(workDir, ddxroot.DirName, "config.yaml"))
290		if err != nil {
291			t.Fatal(err)
292		}
293		if !strings.Contains(string(cfgData), "code-reviewer") {
294			t.Fatalf("personaBind did not write .ddx/config.yaml: %s", cfgData)
295		}
296	}
