298	func TestGraphQLQueueSummaryInProgressCountsFreshActiveWorkers(t *testing.T) {
299		workDir, store := setupIntegrationDir(t)
300	
301		active := &bead.Bead{Title: "active bead", Status: bead.StatusOpen}
302		if err := store.Create(context.Background(), active); err != nil {
303			t.Fatal(err)
304		}
305		if err := workerstatus.WriteLiveness(workDir, "worker-queue-summary", workerstatus.LivenessRecord{
306			WorkerID:       "worker-queue-summary",
307			ProjectRoot:    workDir,
308			CurrentBead:    active.ID,
309			AttemptID:      "att-queue-summary",
310			Phase:          "running",
311			LastActivityAt: time.Now().UTC(),
312		}); err != nil {
313			t.Fatal(err)
314		}
315	
316		state := newTestStateProvider(workDir, store)
317		projectID := state.projects[0].ID
318		h := newGQLHandler(state, workDir, nil)
319	
320		resp := gqlPost(t, h, `{
321			queueSummary(projectId: "`+projectID+`") {
322				ready
323				blocked
324				inProgress
325				operatorAttention
326				dependencyWaiting
327				externalBlocked
328				cancelled
329			}
330		}`)
331		var data struct {
332			QueueSummary struct {
333				Ready             int `json:"ready"`
334				Blocked           int `json:"blocked"`
335				InProgress        int `json:"inProgress"`
336				OperatorAttention int `json:"operatorAttention"`
337				DependencyWaiting int `json:"dependencyWaiting"`
338				ExternalBlocked   int `json:"externalBlocked"`
339				Cancelled         int `json:"cancelled"`
340			} `json:"queueSummary"`
341		}
342		if err := json.Unmarshal(resp["data"], &data); err != nil {
343			t.Fatalf("parse: %v", err)
344		}
345		if data.QueueSummary.InProgress != 1 {
346			t.Fatalf("queueSummary.inProgress: want 1 fresh active worker, got %d", data.QueueSummary.InProgress)
347		}
348	}
